import{_ as e,o,c as s,ag as r}from"./chunks/framework.BbyMWZAR.js";const p=JSON.parse('{"title":"页面性能优化的整体思路与 Web Vitals","description":"","frontmatter":{"title":"页面性能优化的整体思路与 Web Vitals","difficulty":"hard","tags":["性能优化","Web Vitals","LCP","CLS","INP","FCP"],"estimate":30},"headers":[],"relativePath":"domains/browser/qa/qa-17-performance-web-vitals.md","filePath":"domains/browser/qa/qa-17-performance-web-vitals.md","lastUpdated":1783504823000}'),i={name:"domains/browser/qa/qa-17-performance-web-vitals.md"};function n(l,t,a,d,g,c){return o(),s("div",null,[...t[0]||(t[0]=[r(`<h1 id="问答-17-高级-页面性能优化的整体思路与-web-vitals" tabindex="-1">问答 17（高级）：页面性能优化的整体思路与 Web Vitals <a class="header-anchor" href="#问答-17-高级-页面性能优化的整体思路与-web-vitals" aria-label="Permalink to &quot;问答 17（高级）：页面性能优化的整体思路与 Web Vitals&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>前端性能优化如何做？请从网络层、渲染层、代码层、监控层给出系统性的思路，并说明常见的性能指标（FCP / LCP / CLS / INP / TTFB / TBT）分别衡量什么、如何优化。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>整体思路：从「用户感知」倒推到工程手段</strong></p><p><strong>1. 网络层</strong></p><ul><li><strong>减少请求数</strong>：合并小图为雪碧图 / SVG symbol、内联关键 CSS / 小图片、合理拆包。</li><li><strong>减小请求体</strong>：Gzip / Brotli、Tree Shaking、代码压缩、图片压缩（WebP / AVIF）、字体子集化。</li><li><strong>利用缓存</strong>：强缓存 + 协商缓存，HTML 短 / 静态资源长且带 hash。</li><li><strong>加速传输</strong>：CDN、HTTP/2 / 3、Keep-Alive、DNS Prefetch、<code>preconnect</code>、<code>preload</code>。</li><li><strong>早期提示</strong>：<code>103 Early Hints</code> 提前告知客户端预加载资源。</li></ul><p><strong>2. 渲染层</strong></p><ul><li><strong>关键渲染路径</strong>：把首屏关键 CSS inline、非关键 CSS 用 <code>preload</code> + <code>media</code> 异步、脚本 <code>defer</code> / <code>async</code>。</li><li><strong>SSR / SSG / ISR</strong>：把 HTML 在服务端生成好，避免白屏依赖 JS。</li><li><strong>骨架屏 / 占位图</strong>：改善白屏体感，同时避免 CLS。</li><li><strong>图片</strong>：<code>loading=&quot;lazy&quot;</code>、<code>srcset</code>、<code>sizes</code>、<code>fetchpriority=&quot;high&quot;</code> 给首屏大图。</li><li><strong>字体</strong>：<code>font-display: swap</code>、子集化、<code>preload</code> 关键字体。</li><li><strong>减少重绘 / 重排</strong>：合成层动画（transform / opacity）、避免布局抖动。</li></ul><p><strong>3. 代码层</strong></p><ul><li><strong>代码分割</strong>：动态 <code>import()</code>、按路由 / 组件切包。</li><li><strong>减少运行时开销</strong>：避开大而无用的库、<code>lodash-es</code> + tree shake、<code>dayjs</code> 替代 <code>moment</code>。</li><li><strong>虚拟列表 / 分页</strong>：DOM 数量控制。</li><li><strong>Web Worker</strong>：把重计算移到线程，主线程保持响应。</li><li><strong>缓存计算</strong>：<code>useMemo</code>、<code>React.memo</code>、Vue <code>computed</code>。</li><li><strong>减少不必要状态更新</strong> / 事件监听。</li><li><strong>图片解码优化</strong>：<code>decoding=&quot;async&quot;</code>、<code>content-visibility: auto</code>。</li></ul><p><strong>4. 监控层</strong></p><ul><li><strong>RUM（Real User Monitoring）</strong>：<code>web-vitals</code> 库上报，采样。</li><li><strong>合成监控（Synthetic）</strong>：Lighthouse、WebPageTest 定期跑。</li><li><strong>数据分层</strong>：分区域 / 网络 / 机型看指标 P75 / P95。</li><li><strong>报警与灰度</strong>：新版本上线看指标是否退化，退化则回滚。</li></ul><p><strong>Web Vitals（Google 核心网页指标）</strong></p><table tabindex="0"><thead><tr><th>指标</th><th>定义</th><th>优 / 良 / 差阈值（移动端）</th><th>关注点</th></tr></thead><tbody><tr><td><strong>FCP</strong> First Contentful Paint</td><td>首个内容绘制</td><td>≤1.8s / ≤3s / &gt;3s</td><td>TTFB + 关键渲染路径</td></tr><tr><td><strong>LCP</strong> Largest Contentful Paint</td><td>最大内容绘制</td><td>≤2.5s / ≤4s / &gt;4s</td><td>首屏最大元素（图 / 大标题）加载</td></tr><tr><td><strong>CLS</strong> Cumulative Layout Shift</td><td>累计布局偏移</td><td>≤0.1 / ≤0.25 / &gt;0.25</td><td>元素尺寸、字体切换、动态插入</td></tr><tr><td><strong>INP</strong> Interaction to Next Paint</td><td>交互到下一帧</td><td>≤200ms / ≤500ms / &gt;500ms</td><td>主线程繁忙、事件处理耗时</td></tr><tr><td><strong>TTFB</strong> Time to First Byte</td><td>首字节时间</td><td>≤0.8s / ≤1.8s / &gt;1.8s</td><td>DNS / TCP / TLS / 服务端处理</td></tr><tr><td><strong>TBT</strong> Total Blocking Time</td><td>主线程被阻塞的总时间</td><td>≤200ms / ≤600ms / &gt;600ms</td><td>长任务</td></tr></tbody></table><ul><li>2024 起 <strong>INP 替代了 FID</strong>：FID 只看首次交互延迟，INP 看所有交互的最慢一次，更接近真实体感。</li></ul><p><strong>如何度量</strong></p><div class="language-js vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { onLCP, onCLS, onINP, onFCP, onTTFB } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;web-vitals&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">onLCP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sendToAnalytics);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">onCLS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sendToAnalytics);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">onINP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sendToAnalytics);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="追问-1-lcp-长期偏高-怎么系统地优化" tabindex="-1">追问 1：LCP 长期偏高，怎么系统地优化？ <a class="header-anchor" href="#追问-1-lcp-长期偏高-怎么系统地优化" aria-label="Permalink to &quot;追问 1：LCP 长期偏高，怎么系统地优化？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>第一步：<strong>定位 LCP 元素</strong>（DevTools Performance 面板 Timings 里的 LCP 标签、或 <code>PerformanceObserver</code> 拿到 element）。</li><li>常见 LCP 元素：首屏大图 / Hero Banner / 大标题文本。</li><li>分段优化： <ol><li><strong>TTFB</strong>：CDN 边缘缓存 HTML，SSR 缓存化，减少服务端渲染开销；用 <code>103 Early Hints</code> 提前 preload 关键资源。</li><li><strong>资源加载时长</strong>：给 LCP 图片加 <code>fetchpriority=&quot;high&quot;</code>、<code>preload</code>；用 WebP/AVIF 减小体积；避免懒加载首屏图。</li><li><strong>渲染延迟</strong>：关键 CSS 内联；避免 JS 阻塞（<code>defer</code>）；避免字体切换让文字重绘。</li><li><strong>客户端渲染改 SSR</strong>：首屏由服务端产出 HTML，让 LCP 元素随首屏 HTML 一起下发。</li><li><strong>减少客户端水合的重工</strong>：Streaming SSR、Islands 架构、Selective Hydration。</li></ol></li><li>观测：拿掉每一个「候选 LCP」元素看其它候选，是否也慢，逐步定位瓶颈。</li></ul><h2 id="追问-2-ttfb-高一般是哪些原因" tabindex="-1">追问 2：TTFB 高一般是哪些原因？ <a class="header-anchor" href="#追问-2-ttfb-高一般是哪些原因" aria-label="Permalink to &quot;追问 2：TTFB 高一般是哪些原因？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>网络路径</strong>：跨地域 / 弱网 / DNS 慢 / 无 HTTP/2 复用。</li><li><strong>握手</strong>：TLS 握手多 RTT；未启用 session resumption / 0-RTT。</li><li><strong>CDN 未命中</strong>：回源慢；源站冷启动、无 shield。</li><li><strong>服务端处理慢</strong>：数据库慢查询、下游 RPC 慢、GC / 内存抖动、SSR 渲染耗时。</li><li><strong>重定向 / 认证跳转</strong>：多次 3xx 累积时间。</li><li>优化路径： <ul><li>边缘 SSR / 边缘计算（Cloudflare Workers、Vercel Edge）。</li><li>CDN 缓存 HTML（Stale-While-Revalidate）。</li><li>数据 SSR 部分静态化 + 客户端补数据。</li><li>服务端引入 Streaming（一部分 HTML 先吐给浏览器，边渲染边等数据）。</li></ul></li></ul><h2 id="追问-3-怎么防止「inp-抖动」——用户偶尔点一下按钮卡半秒" tabindex="-1">追问 3：怎么防止「INP 抖动」——用户偶尔点一下按钮卡半秒？ <a class="header-anchor" href="#追问-3-怎么防止「inp-抖动」——用户偶尔点一下按钮卡半秒" aria-label="Permalink to &quot;追问 3：怎么防止「INP 抖动」——用户偶尔点一下按钮卡半秒？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>INP 关注<strong>所有交互中最差的一次</strong>，任何一次长任务都可能拉高。</li><li>排查： <ul><li><code>PerformanceObserver({ type: &#39;event&#39;, durationThreshold: 40 })</code> 上报慢事件及其栈。</li><li>DevTools Performance 录制交互，看主线程哪段任务是 long task。</li></ul></li><li>优化： <ul><li><strong>拆长任务</strong>：把大批量计算切成小片，<code>scheduler.postTask</code> 或 <code>setTimeout(0)</code> / <code>MessageChannel</code> 让出主线程。</li><li><strong>异步化 / Web Worker</strong>：数据处理放 worker。</li><li><strong>减少同步 IO</strong>：避免 <code>localStorage</code> 一次读大量数据、避免同步布局读写。</li><li><strong>框架层</strong>：React 18 的 <code>startTransition</code> / concurrent rendering、Vue 的 <code>defineAsyncComponent</code> 拆包。</li><li><strong>事件节流 / 防抖</strong>：input、scroll、resize 用 rAF 或 debounce。</li><li><strong>测量优先级</strong>：<code>Priority Hints</code>、<code>fetchpriority</code> 让关键资源先来。</li></ul></li><li>上线后跟踪 INP P75，配合灰度回滚机制。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://web.dev/articles/vitals" target="_blank" rel="noreferrer">web.dev: Web Vitals</a>：LCP、INP、CLS 定义与测量</li><li><a href="https://www.w3.org/webperf/" target="_blank" rel="noreferrer">W3C: Web Performance</a>：性能指标规范制定</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/API/Performance_API" target="_blank" rel="noreferrer">MDN: Performance APIs</a>：Performance API 与指标采集</li></ul>`,30)])])}const u=e(i,[["render",n]]);export{p as __pageData,u as default};
